"use client"

import { useState, useEffect, useTransition } from "react"
import { useRouter } from "next/navigation"
import { toast } from "sonner"
import { addDonation } from "@/app/actions/donations"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"

declare global {
  interface Window {
    paypal: any;
  }
}

const PAYPAL_CLIENT_ID = "AYox6gTBsCeaw9y9C3IRGzroo4HQCkuJRiAQDsJkcMcbvYhwDnk4CkVMWEvQNNv18gPpx-PZzNlNDsg1";

export function DonationForm() {
  const router = useRouter()
  const [name, setName] = useState("")
  const [amount, setAmount] = useState("")
  const [isPending, startTransition] = useTransition()

  // ✅ Load PayPal button
  useEffect(() => {
    const existingScript = document.querySelector("#paypal-script")

    if (!existingScript) {
      const script = document.createElement("script")
      script.id = "paypal-script"
      script.src = `https://www.paypal.com/sdk/js?client-id=${PAYPAL_CLIENT_ID}&currency=USD`
      script.async = true

      script.onload = renderPayPalButtons

      document.body.appendChild(script)
    } else {
      renderPayPalButtons()
    }

    function renderPayPalButtons() {
      if (!window.paypal) return

      const container = document.getElementById("paypal-button")
      if (!container) return

      container.innerHTML = ""

      window.paypal.Buttons({
        createOrder: (data: any, actions: any) => {
          const parsed = parseFloat(amount)

          if (!name.trim()) {
            toast.error("Enter your name first")
            return
          }

          if (!parsed || parsed <= 0) {
            toast.error("Enter a valid amount")
            return
          }

          return actions.order.create({
            purchase_units: [
              {
                amount: {
                  value: parsed.toFixed(2)
                }
              }
            ]
          })
        },

        onApprove: (data: any, actions: any) => {
          return actions.order.capture().then((details: any) => {

            const payerName =
              name.trim() || details.payer.name.given_name

            toast.success(`Thank you ${payerName}!`)

            startTransition(async () => {
              const result = await addDonation({
                name: payerName,
                amount: parseFloat(amount)
              })

              if (result?.error) {
                toast.error(result.error)
                return
              }

              setName("")
              setAmount("")
              router.refresh()
            })
          })
        }
      }).render("#paypal-button")
    }

  }, [name, amount, router])

  return (
    <div className="flex flex-col gap-4">

      {/* NAME */}
      <div className="flex flex-col gap-2">
        <Label htmlFor="donor-name">Your name</Label>
        <Input
          id="donor-name"
          placeholder="e.g. Jane Doe"
          value={name}
          onChange={(e) => setName(e.target.value)}
        />
      </div>

      {/* AMOUNT */}
      <div className="flex flex-col gap-2">
        <Label htmlFor="donor-amount">Amount (USD)</Label>
        <Input
          id="donor-amount"
          type="number"
          min="1"
          placeholder="10"
          value={amount}
          onChange={(e) => setAmount(e.target.value)}
        />
      </div>

      {/* PAYPAL BUTTON */}
      <div id="paypal-button" />

      <p className="text-sm text-muted-foreground">
        Secure payment via PayPal
      </p>
    </div>
  )
}